def make_tag(tag, content, **attrs):
    attr_str = ''.join(f' {k}="{v}"' for k, v in attrs.items())
    return f'<{tag}{attr_str}>{content}</{tag}>'

hard.solution:
def enforce_types(**type_specs):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for param, expected_type in type_specs.items():
                if param in kwargs and not isinstance(kwargs[param], expected_type):
                    raise TypeError(f'{param} must be {expected_type}')
            return func(*args, **kwargs)
        return wrapper
    return decorator
